// client/src/services/assistantService.js
export async function askAssistant(query) {
  if (!query || query.trim() === '') {
    console.warn('Assistant: Empty query provided');
    return 'Please provide a question or command.';
  }

  try {
    console.log('📤 Sending query to assistant:', query);
    const resp = await fetch("/api/assistant", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ query }),
    });

    console.log(`📥 Assistant response status: ${resp.status}`);

    if (!resp.ok) {
      const errorData = await resp.json().catch(() => ({}));
      console.error('Assistant API error:', resp.status, errorData);
      
      if (resp.status === 400) return 'Invalid request. Please try again.';
      if (resp.status === 500) {
        // More specific error from server
        return errorData?.error || 'The assistant service is having trouble. Please check your API configuration.';
      }
      
      throw new Error(`HTTP ${resp.status}: ${errorData?.error || 'Failed to reach assistant'}`);
    }

    const data = await resp.json();
    console.log('Assistant response:', data);

    return data.reply || 'No response from assistant.';
  } catch (err) {
    console.error("❌ Assistant service error:", err.message, err);
    
    // Provide actionable error message
    if (err.message.includes('Failed to fetch')) {
      return 'Cannot reach the server. Make sure it is running on localhost:5000.';
    }
    
    return 'Sorry, the assistant could not respond. ' + (err.message || 'Please try again.');
  }
}
